#include <bits/stdc++.h>
using namespace std;

struct tree {
    int l, r;
    int s, lazy;
} sl[400005], sr[400005];

int n, m;

void push_up(tree t[], int p) {
    t[p].s = t[p * 2].s + t[p * 2 + 1].s;
}

void push_down(tree t[], int p) {
    t[p * 2].lazy += t[p].lazy;
    t[p * 2 + 1].lazy += t[p].lazy;
    t[p * 2].s += (t[p * 2].r - t[p * 2].l + 1) * t[p].lazy;
    t[p * 2 + 1].s += (t[p * 2 + 1].r - t[p * 2 + 1].l + 1) * t[p].lazy;
    t[p].lazy = 0;
}

void build(tree t[], int l, int r, int p) {
    t[p].l = l, t[p].r = r;
    if (l == r) return ;
    int mid = l + (r - l) / 2;
    build(t, l, mid, p * 2);
    build(t, mid + 1, r, p * 2 + 1);
}

void add(tree t[], int l, int r, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].s += t[p].r - t[p].l + 1;
        t[p].lazy++;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(t, p);
    add(t, l, r, p * 2);
    add(t, l, r, p * 2 + 1);
    push_up(t, p);
}

int query(tree t[], int k, int p) {
    if (t[p].r < k || t[p].l > k) {
        return 0;
    }
    if (t[p].l == t[p].r) {
        return t[p].s;
    }
    push_down(t, p);
    return query(t, k, p * 2) + query(t, k, p * 2 + 1);
}

int main() {
    cin >> n >> m;
    build(sl, 1, n, 1);
    build(sr, 1, n, 1);
    while (m--) {
        int q, l, r;
        cin >> q >> l >> r;
        if (q == 1) {
            add(sl, l, n, 1);
            add(sr, r, n, 1);
        }
        else {
            cout << query(sl, r, 1) - query(sr, l - 1, 1) << endl;
        }
    }
    return 0;
}
